import{_ as s,o as e,c as n,ag as t}from"./chunks/framework.ePeAWSvT.js";const h=JSON.parse('{"title":"MemoryAgent 架构说明","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture/memory-agent.md","filePath":"guide/architecture/memory-agent.md"}'),o={name:"guide/architecture/memory-agent.md"};function p(r,a,l,i,c,d){return e(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="memoryagent-架构说明" tabindex="-1">MemoryAgent 架构说明 <a class="header-anchor" href="#memoryagent-架构说明" aria-label="Permalink to &quot;MemoryAgent 架构说明&quot;">​</a></h1><p>本文描述 <code>MemoryAgent</code> 的模块分层、数据流与关键决策，面向工程维护与架构理解。</p><h2 id="定位与职责" tabindex="-1">定位与职责 <a class="header-anchor" href="#定位与职责" aria-label="Permalink to &quot;定位与职责&quot;">​</a></h2><p><code>MemoryAgent</code> 是 VTuber 链路的<strong>编排器</strong>，职责是将 <code>AgentCore</code> 的 token 流接入 TTS / Live2D pipeline。</p><p>它<strong>不做</strong>：</p><ul><li>LLM 调用（委托给 AgentCore）</li><li>工具调用（委托给 AgentCore + ToolManager）</li><li>Prompt 拼装（委托给 AgentCore → PromptBuilder）</li><li>Vision 摘要（委托给 AgentCore → VisionSummarizer）</li></ul><p>它<strong>只做</strong>：</p><ul><li>从 <code>AgentCore.run_turn()</code> 消费 token 流</li><li>断句 → 表情/动作提取 → TTS 过滤 → 显示处理</li><li>维护 <code>MemoryStore</code>（memory + history + interrupt）</li></ul><h2 id="模块分层" tabindex="-1">模块分层 <a class="header-anchor" href="#模块分层" aria-label="Permalink to &quot;模块分层&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MemoryAgent (agent.py)                ← 编排器</span></span>
<span class="line"><span>├── AgentCore (core.py)               ← 共享核心（tool / vision / prompt / LLM）</span></span>
<span class="line"><span>│   ├── AsyncLLM.stream_with_tools()  ← 统一流式 tool calling</span></span>
<span class="line"><span>│   ├── VisionSummarizer              ← 图片摘要</span></span>
<span class="line"><span>│   ├── PromptBuilder                 ← UserPromptBlock 拼装</span></span>
<span class="line"><span>│   └── ConversationStorage           ← MemoryStoreAdapter（写回由 MemoryAgent 接管）</span></span>
<span class="line"><span>├── MemoryStore (memory_store.py)     ← memory / history / interrupt</span></span>
<span class="line"><span>├── MessageFactory (message_factory.py) ← 消息解析与构造</span></span>
<span class="line"><span>└── Transformers 管线 (transformers.py)</span></span>
<span class="line"><span>    sentence_divider → actions_extractor → tts_filter → display_processor</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">AgentCore.write_back = False</p><p><code>MemoryAgent</code> 初始化时将 <code>core.write_back</code> 设为 <code>False</code>，由 MemoryAgent 自身统一负责写回 <code>MemoryStore</code>。这样 assistant message 的写入时机与 TTS 流程对齐，避免双写。</p></div><h2 id="数据流" tabindex="-1">数据流 <a class="header-anchor" href="#数据流" aria-label="Permalink to &quot;数据流&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>📥 BatchInput（用户输入：文本 + 可选图片）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>✉️ MessageFactory.build_user_message_from_batch()</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>💬 AgentCore.run_turn(user_text, user_images)</span></span>
<span class="line"><span>    ─────────────────────────────────────────</span></span>
<span class="line"><span>    │  [vision 预处理] VisionSummarizer</span></span>
<span class="line"><span>    │  [prompt 拼装]   PromptBuilder</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    │  chat_llm.stream_with_tools(messages, tools=schema)</span></span>
<span class="line"><span>    │  loop:</span></span>
<span class="line"><span>    │    text delta → yield str</span></span>
<span class="line"><span>    │    tool_call  → yield [🔧 name] → execute → continue</span></span>
<span class="line"><span>    │    stop       → break</span></span>
<span class="line"><span>    ─────────────────────────────────────────</span></span>
<span class="line"><span>    ↓ yield str tokens</span></span>
<span class="line"><span>🔄 Transformers 管线</span></span>
<span class="line"><span>    sentence_divider      # 按标点断句</span></span>
<span class="line"><span>      → actions_extractor # 提取 [emotion]/[sound] 等动作标签</span></span>
<span class="line"><span>      → tts_filter        # 过滤 [think]/[🔧 ...] 等不朗读内容</span></span>
<span class="line"><span>      → display_processor # 处理显示文本（think 折叠等）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>📤 yield SentenceOutput</span></span>
<span class="line"><span>    ├── display_text  # 字幕 / 弹幕</span></span>
<span class="line"><span>    ├── tts_text      # 送 TTS 朗读的文本（已过滤标签）</span></span>
<span class="line"><span>    └── actions       # Live2D 动作 / 表情 / 音效</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>💾 MemoryStore.add_message()  # 写回 user + assistant message</span></span></code></pre></div><h2 id="关键设计决策" tabindex="-1">关键设计决策 <a class="header-anchor" href="#关键设计决策" aria-label="Permalink to &quot;关键设计决策&quot;">​</a></h2><h3 id="工具状态标签不朗读" tabindex="-1">工具状态标签不朗读 <a class="header-anchor" href="#工具状态标签不朗读" aria-label="Permalink to &quot;工具状态标签不朗读&quot;">​</a></h3><p><code>AgentCore</code> 在执行工具前 yield <code>[🔧 tool_name]</code> 标签。<code>tts_filter</code> 依据 <code>ignore_brackets</code> 配置过滤掉方括号内容（或通过 tag 机制识别），保证 TTS 不读出工具状态，但字幕仍可展示。</p><h3 id="vision-决策" tabindex="-1">Vision 决策 <a class="header-anchor" href="#vision-决策" aria-label="Permalink to &quot;Vision 决策&quot;">​</a></h3><p><code>chat_supports_vision</code>（来自 <code>lab.toml</code> 的 <code>[agent.chat_model]</code>）决定图片处理方式：</p><table tabindex="0"><thead><tr><th>chat_supports_vision</th><th>require_detailed</th><th>行为</th></tr></thead><tbody><tr><td>False</td><td>any</td><td>必须生成 vision 摘要，纯文本喂 chat</td></tr><tr><td>True</td><td>False</td><td>图片直接喂 chat，不生成摘要</td></tr><tr><td>True</td><td>True</td><td>图片喂 chat + 同步生成逐图摘要（双保险）</td></tr></tbody></table><h3 id="history-不存-base64" tabindex="-1">History 不存 base64 <a class="header-anchor" href="#history-不存-base64" aria-label="Permalink to &quot;History 不存 base64&quot;">​</a></h3><p><code>MemoryStore</code> 写回时只存文本内容，不保留图片 base64，避免 memory 文件膨胀。</p><h3 id="tool-图与用户图隔离" tabindex="-1">Tool 图与用户图隔离 <a class="header-anchor" href="#tool-图与用户图隔离" aria-label="Permalink to &quot;Tool 图与用户图隔离&quot;">​</a></h3><ul><li>工具回调图：标签 <code>tool1</code>，来源 <code>source=&quot;tool&quot;</code></li><li>用户上传图：标签 <code>p1</code>/<code>p2</code>/...，来源 <code>source=&quot;upload&quot;</code></li></ul><p>两类图片在 vision 摘要和 prompt 注入时分开处理，不混用标签。</p><h2 id="扩展点" tabindex="-1">扩展点 <a class="header-anchor" href="#扩展点" aria-label="Permalink to &quot;扩展点&quot;">​</a></h2><ul><li><strong>多工具截图</strong>：在 ToolManager 侧收集多张 tool 图，给出 <code>tool1/tool2...</code> 标签（目前默认单张）</li><li><strong>支持 http(s) 图片</strong>：在 <code>MessageFactory.extract_text_and_data_images</code> 扩展</li><li><strong>自定义断句</strong>：<code>segment_method</code> 支持 <code>pysbd</code> / 自定义标点规则</li><li><strong>中断方式</strong>：<code>interrupt_method=system</code>（注入 system message）或 <code>user</code>（注入 user message）</li></ul>`,26)])])}const u=s(o,[["render",p]]);export{h as __pageData,u as default};
